vector<int> split(const string&
str, const string& delimiter) {
vector<int>
result;
size_t start = 0;
size_t end =
str.find(delimiter);
while (end !=
string::npos) {
result.push_back(stoi(str.substr(start, end - start)));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(stoi(str.substr(start)));
return result;
}
